    73→	const { tooltipBg, tooltipBorder, gridStroke, axisStroke } = useChartTheme();
    74→	const [selectedMetric, setSelectedMetric] = useState<MetricType>("sessions");
    75→
    76→	const currentMetric = METRICS[selectedMetric];
    77→
