    79→	const projectTotals = data.reduce((acc, d) => {
    80→		const current = acc.get(d.project_path) || 0;
    81→		acc.set(d.project_path, current + d.sessions);
    82→		return acc;
    83→	}, new Map<string, number>());
    84→
