    94→			}
    95→
    96→			cumulativeData.push(cumulativeItem);
    97→		}
    98→
    99→		return cumulativeData;
   100→	}, [data, isCumulative, seriesKeys]);
   101→
   102→	const getDisplayName = (key: string): string => {
