							tickFormatter={currentMetric.formatter}
							domain={[0, 100]}
						/>
						<Tooltip
							contentStyle={{
								backgroundColor: tooltipBg,
								border: `1px solid ${tooltipBorder}`,
								borderRadius: "8px",
								padding: "12px",
							}}
							formatter={(value, name) => {
								if (!name || name === "date" || name === "displayDate")
									return null;
								return [
									currentMetric.formatter((value as number) ?? 0),
									formatProjectName(String(name)),
								];
							}}
							labelFormatter={(label) => label}
						/>
						<Legend
							formatter={(value) => formatProjectName(value)}
							wrapperStyle={{ paddingTop: "20px" }}
						/>
						{topProjects.map((projectPath, index) => (
							<Line
								key={projectPath}
								type="monotone"
								dataKey={projectPath}
								stroke={PROJECT_COLORS[index % PROJECT_COLORS.length]}
								strokeWidth={2}
								dot={{ r: 3 }}
								activeDot={{ r: 5 }}
								connectNulls
							/>
						))}
					</LineChart>
				) : (
					<AreaChart
						data={chartData}
						margin={{ top: 10, right: 30, left: 0, bottom: 0 }}
					>
						<CartesianGrid strokeDasharray="3 3" stroke={gridStroke} />
						<XAxis
							dataKey="displayDate"
							stroke={axisStroke}
							style={{ fontSize: "12px" }}
							angle={-45}
							textAnchor="end"
							height={80}
						/>
						<YAxis
							stroke={axisStroke}
							style={{ fontSize: "12px" }}
							tickFormatter={currentMetric.formatter}
						/>
						<Tooltip
							contentStyle={{
								backgroundColor: tooltipBg,
								border: `1px solid ${tooltipBorder}`,
								borderRadius: "8px",
								padding: "12px",
							}}
							formatter={(value, name) => {
								if (!name || name === "date" || name === "displayDate")
									return null;
								return [
									currentMetric.formatter((value as number) ?? 0),
									formatProjectName(String(name)),
								];
							}}
							labelFormatter={(label) => label}
						/>
						<Legend
							formatter={(value) => formatProjectName(value)}
							wrapperStyle={{ paddingTop: "20px" }}
						/>
						{topProjects.map((projectPath, index) => (
							<Area
								key={projectPath}
								type="monotone"
								dataKey={projectPath}
								stackId="1"
								stroke={PROJECT_COLORS[index % PROJECT_COLORS.length]}
								fill={PROJECT_COLORS[index % PROJECT_COLORS.length]}
								fillOpacity={0.6}
								strokeWidth={2}
							/>
						))}
					</AreaChart>
				)}
			</ResponsiveContainer>

			{projectTotals.size > maxProjects && (
				<p className="text-sm text-muted text-center">
					Showing top {maxProjects} of {projectTotals.size} projects
				</p>
			)}
		</div>
	);
}

