     2→import { Activity, Clock, TrendingUp, Zap } from "lucide-react";
     3→import { useState } from "react";
     4→import {
     5→	Area,
     6→	AreaChart,
     7→	CartesianGrid,
     8→	Legend,
     9→	Line,
    10→	LineChart,
    11→	ResponsiveContainer,
    12→	Tooltip,
    13→	XAxis,
    14→	YAxis,
    15→} from "recharts";
    16→import { useChartTheme } from "@/hooks/useChartTheme";
    17→
    18→interface ProjectTrendChartProps {
    19→	data: ProjectTrendDataPoint[];
    20→	maxProjects?: number;
    21→}
    22→
    23→type MetricType = "sessions" | "hours" | "tokens" | "success_rate";
    24→
    25→const METRICS = {
    26→	sessions: {
    27→		key: "sessions",
    28→		label: "Sessions",
    29→		icon: Activity,
    30→		formatter: (value: number) => value.toLocaleString(),
    31→	},
    32→	hours: {
    33→		key: "total_hours",
    34→		label: "Hours",
    35→		icon: Clock,
    36→		formatter: (value: number) => `${value.toFixed(1)}h`,
    37→	},
    38→	tokens: {
    39→		key: "total_tokens",
    40→		label: "Tokens",
    41→		icon: Zap,
    42→		formatter: (value: number) => {
    43→			if (value >= 1_000_000) return `${(value / 1_000_000).toFixed(1)}M`;
    44→			if (value >= 1_000) return `${(value / 1_000).toFixed(1)}K`;
    45→			return value.toFixed(0);
    46→		},
    47→	},
    48→	success_rate: {
    49→		key: "avg_success_rate",
    50→		label: "Success Rate",
    51→		icon: TrendingUp,
    52→		formatter: (value: number) => `${value.toFixed(0)}%`,
    53→	},
    54→};
    55→
    56→const PROJECT_COLORS = [
    57→	"#3b82f6",
    58→	"#10b981",
    59→	"#f59e0b",
    60→	"#8b5cf6",
    61→	"#ef4444",
    62→	"#ec4899",
    63→	"#14b8a6",
    64→	"#f97316",
    65→	"#6366f1",
    66→	"#84cc16",
    67→];
    68→
    69→export function ProjectTrendChart({
    70→	data,
    71→	maxProjects = 10,
    72→}: ProjectTrendChartProps) {
    73→	const { tooltipBg, tooltipBorder, gridStroke, axisStroke } = useChartTheme();
    74→	const [selectedMetric, setSelectedMetric] = useState<MetricType>("sessions");
    75→
    76→	const currentMetric = METRICS[selectedMetric];
    77→
    78→	// Get top projects by total sessions
    79→	const projectTotals = data.reduce((acc, d) => {
    80→		const current = acc.get(d.project_path) || 0;
    81→		acc.set(d.project_path, current + d.sessions);
    82→		return acc;
    83→	}, new Map<string, number>());
    84→
    85→	const topProjects = Array.from(projectTotals.entries())
    86→		.sort((a, b) => b[1] - a[1])
    87→		.slice(0, maxProjects)
    88→		.map(([path]) => path);
    89→
    90→	const filteredData = data.filter((d) => topProjects.includes(d.project_path));
    91→	const existingDates = Array.from(
