		const projectTotals = new Map<string, number>();
		for (const d of data) {
			projectTotals.set(d.project_path, (projectTotals.get(d.project_path) ?? 0) + d.sessions);
		}
		const sorted = Array.from(projectTotals.entries()).sort((a, b) => b[1] - a[1]);
		const top = sorted.slice(0, MAX_SERIES).map(([p]) => p);
