    94→export const DimensionAnalysisChart = memo(function DimensionAnalysisChart({
    95→	data,
    96→	dimension,
    97→	metric,
    98→	split_by,
    99→	showPercentage = false,
   100→	userMap,
   101→}: DimensionAnalysisChartProps) {
   102→	const { gridStroke, axisStroke } = useChartTheme();
   103→
   104→	const { chartData, dataKeys } = useMemo(() => {
   105→		if (!data || data.length === 0) {
   106→			return { chartData: [], dataKeys: [] };
   107→		}
   108→
   109→		let chartData: Record<string, unknown>[] = [];
   110→		let dataKeys: string[] = [];
   111→
   112→		if (split_by && data[0].split_values) {
   113→			const allSplitValues = new Set<string>();
   114→			for (const item of data) {
   115→				if (item.split_values) {
   116→					for (const key of Object.keys(item.split_values)) {
   117→						allSplitValues.add(key);
   118→					}
   119→				}
   120→			}
   121→			dataKeys = Array.from(allSplitValues);
   122→
   123→			chartData = data.map((item) => {
   124→				const row: Record<string, unknown> = {
   125→					name: formatDimensionValue(item.dimension_value, dimension, userMap),
   126→					_fullName: item.dimension_value,
   127→					_total: 0,
   128→					_originalValues: {} as Record<string, number>,
   129→				};
   130→				const origValues = row._originalValues as Record<string, number>;
   131→				let total = 0;
   132→				for (const key of dataKeys) {
   133→					const val = item.split_values?.[key] || 0;
   134→					origValues[key] = val;
   135→					total += val;
   136→				}
   137→				row._total = total;
   138→
   139→				if (showPercentage && total > 0) {
   140→					for (const key of dataKeys) {
   141→						row[key] = (origValues[key] / total) * 100;
   142→					}
   143→				} else {
   144→					for (const key of dataKeys) {
   145→						row[key] = origValues[key];
   146→					}
   147→				}
   148→
   149→				return row;
   150→			});
   151→
   152→			chartData.sort((a, b) => (b._total as number) - (a._total as number));
   153→		} else {
   154→			dataKeys = [formatMetricLabel(metric)];
   155→			chartData = data.map((item) => ({
   156→				name: formatDimensionValue(item.dimension_value, dimension, userMap),
   157→				_fullName: item.dimension_value,
   158→				[formatMetricLabel(metric)]: item.metric_value || 0,
   159→			}));
   160→
   161→			chartData.sort(
   162→				(a, b) =>
   163→					(b[formatMetricLabel(metric)] as number) -
   164→					(a[formatMetricLabel(metric)] as number),
   165→			);
   166→		}
   167→
   168→		return { chartData, dataKeys };
   169→	}, [data, dimension, metric, split_by, showPercentage, userMap]);
   170→
   171→	if (!data || data.length === 0) {
   172→		return (
   173→			<div className="flex items-center justify-center h-64 text-muted">
   174→				No data available for the selected dimension and metric
   175→			</div>
   176→		);
   177→	}
   178→
   179→	const CustomTooltip = ({
   180→		active,
   181→		payload,
   182→		label,
   183→	}: Record<string, unknown>) => {
   184→		if (active && payload && Array.isArray(payload) && payload.length) {
   185→			const payloadData = (payload[0] as Record<string, unknown>)?.payload as
   186→				| Record<string, unknown>
   187→				| undefined;
   188→			const fullName = payloadData?._fullName || label;
   189→			const originalValues = payloadData?._originalValues as
   190→				| Record<string, number>
   191→				| undefined;
   192→
   193→			return (
   194→				<div className="bg-input p-3 border border-border rounded shadow-lg">
   195→					<p className="font-semibold mb-2 text-foreground">
   196→						{fullName as string}
   197→					</p>
   198→					{(payload as Record<string, unknown>[]).map(
   199→						(entry, index: number) => {
   200→							const displayValue =
   201→								originalValues &&
   202→								originalValues[entry.name as string] !== undefined
   203→									? formatNumberWithCommas(originalValues[entry.name as string])
   204→									: typeof entry.value === "number"
   205→										? formatNumberWithCommas(entry.value)
   206→										: entry.value;
   207→
   208→							return (
   209→								<p
   210→									// biome-ignore lint/suspicious/noArrayIndexKey: tooltip payload items
   211→									key={index}
   212→									style={{ color: entry.color as string }}
   213→								>
   214→									{entry.name as string}: {displayValue as string}
   215→									{showPercentage &&
   216→										originalValues &&
   217→										originalValues[entry.name as string] !== undefined && (
   218→											<span className="text-muted ml-1">
   219→												({(entry.value as number).toFixed(1)}%)
   220→											</span>
   221→										)}
   222→								</p>
   223→							);
   224→						},
   225→					)}
   226→				</div>
   227→			);
   228→		}
   229→		return null;
   230→	};
   231→
   232→	return (
   233→		<div className="w-full">
   234→			<ResponsiveContainer width="100%" height={400}>
   235→				<BarChart
   236→					data={chartData}
   237→					layout="vertical"
   238→					margin={{ top: 20, right: 30, left: 10, bottom: 20 }}
   239→				>
   240→					<CartesianGrid strokeDasharray="3 3" stroke={gridStroke} />
   241→					<XAxis
   242→						type="number"
   243→						className="text-xs"
   244→						tick={{ fill: axisStroke }}
   245→						tickFormatter={
   246→							showPercentage && split_by
   247→								? (value) => `${value.toFixed(0)}%`
   248→								: formatCompactNumber
   249→						}
   250→						domain={showPercentage && split_by ? [0, 100] : undefined}
   251→						label={{
   252→							value:
   253→								showPercentage && split_by
   254→									? "Percentage (%)"
   255→									: formatMetricLabel(metric),
   256→							position: "insideBottom",
   257→							offset: -10,
   258→							style: { textAnchor: "middle", fill: axisStroke },
   259→						}}
   260→					/>
   261→					<YAxis
   262→						type="category"
   263→						dataKey="name"
   264→						width={150}
   265→						className="text-xs"
   266→						tick={{ fill: axisStroke, fontSize: 12 }}
   267→						interval={0}
   268→					/>
   269→					<Tooltip content={<CustomTooltip />} />
   270→					{split_by && <Legend wrapperStyle={{ paddingTop: "20px" }} />}
   271→					{split_by ? (
   272→						dataKeys.map((key, index) => (
   273→							<Bar
   274→								key={key}
   275→								dataKey={key}
   276→								stackId="stack"
   277→								fill={CHART_COLORS[index % CHART_COLORS.length]}
   278→							/>
   279→						))
   280→					) : (
   281→						<Bar dataKey={formatMetricLabel(metric)} fill="#3b82f6" />
   282→					)}
   283→				</BarChart>
   284→			</ResponsiveContainer>
   285→		</div>
   286→	);
   287→});
