    67→/**
    68→ * Get session analytics from the materialized view
    69→ */
    70→export async function getSessionAnalytics(
    71→	orgId: string,
    72→	params: {
    73→		days?: number;
    74→		user_id?: string;
    75→		project_path?: string;
    76→		repository?: string;
    77→		limit?: number;
    78→		offset?: number;
    79→		sort_by?: "date" | "duration" | "interactions";
    80→		sort_order?: "asc" | "desc";
    81→	} = {},
    82→): Promise<SessionAnalytics[]> {
    83→	const {
    84→		days = 30,
    85→		user_id,
    86→		project_path,
    87→		repository,
    88→		limit = 50,
    89→		offset = 0,
    90→		sort_by = "date",
    91→		sort_order = "desc",
    92→	} = params;
    93→
    94→	const org = escapeString(orgId);
    95→	const d = Number(days);
    96→	const lim = Number(limit);
    97→	const off = Number(offset);
    98→
    99→	let filters = "";
   100→	if (user_id) {
   101→		filters += ` AND user_id = '${escapeString(user_id)}'`;
   102→	}
   103→	if (project_path) {
   104→		filters += ` AND project_path = '${escapeString(project_path)}'`;
   105→	}
   106→	if (repository) {
   107→		const escapedRepo = escapeString(repository);
   108→		filters += ` AND (git_remote = '${escapedRepo}' OR package_name = '${escapedRepo}' OR project_path = '${escapedRepo}')`;
   109→	}
   110→
   111→	const sortColumn =
   112→		sort_by === "duration"
   113→			? "actual_duration_min"
   114→			: sort_by === "interactions"
   115→				? "total_interactions"
   116→				: "sa.session_date";
   117→	const sortDirection = sort_order === "asc" ? "ASC" : "DESC";
   118→
   119→	const query = `
   120→    SELECT
   121→      session_id,
   122→      user_id,
   123→      formatDateTime(sa.session_date, '%Y-%m-%d %H:%i:%S') as session_date,
   124→      project_path,
   125→      organization_id,
   126→      git_remote,
   127→      package_name,
   128→      total_interactions,
   129→      avg_period_sec,
   130→      median_period_sec,
   131→      quick_responses,
   132→      normal_responses,
   133→      long_pauses,
   134→      actual_duration_min,
   135→      formatDateTime(sa.last_interaction_date, '%Y-%m-%d %H:%i:%S') as last_interaction_date,
   136→      total_tokens,
   137→      input_tokens,
   138→      output_tokens,
   139→      git_sha,
   140→      git_branch,
   141→      has_commit,
   142→      subagent_types,
   143→      skills,
   144→      slash_commands,
   145→      session_archetype,
   146→      success_score,
   147→      error_count,
   148→      model_used,
   149→      used_plan_mode
