   191→export async function getSessionAnalyticsSummary(
   192→	orgId: string,
   193→	params: {
   194→		days?: number;
   195→		user_id?: string;
   196→		project_path?: string;
   197→	} = {},
   198→): Promise<SessionAnalyticsSummary> {
   199→	const { days = 30, user_id, project_path } = params;
   200→	const org = escapeString(orgId);
   201→	const d = Number(days);
   202→
   203→	let filters = "";
   204→	if (user_id) {
   205→		filters += ` AND user_id = '${escapeString(user_id)}'`;
   206→	}
   207→	if (project_path) {
   208→		filters += ` AND project_path = '${escapeString(project_path)}'`;
   209→	}
   210→
   211→	const query = `
   212→    WITH totals AS (
   213→      SELECT
   214→        COUNT(*) as cnt_sessions,
   215→        SUM(total_interactions) as sum_interactions,
   216→        SUM(quick_responses) as sum_quick_responses,
   217→        SUM(long_pauses) as sum_long_pauses,
   218→        ifNull(AVG(actual_duration_min), 0) as avg_duration,
   219→        ifNull(AVG(total_interactions), 0) as avg_interactions,
   220→        ifNull(AVG(avg_period_sec), 0) as avg_response,
   221→        ifNull(AVG(median_period_sec), 0) as med_response,
   222→        countIf(length(subagent_types) > 0) as cnt_subagents,
   223→        countIf(length(skills) > 0) as cnt_skills,
   224→        countIf(length(slash_commands) > 0) as cnt_slash
   225→      FROM rudel.session_analytics
   226→      WHERE ${buildDateFilter(d)}
   227→        AND organization_id = '${org}'
   228→        ${filters}
   229→    )
   230→    SELECT
   231→      cnt_sessions as total_sessions,
   232→      sum_interactions as total_interactions,
   233→      ifNull(round(avg_duration, 2), 0) as avg_session_duration_min,
   234→      ifNull(round(avg_interactions, 2), 0) as avg_interactions_per_session,
   235→      ifNull(round(avg_response, 2), 0) as avg_response_time_sec,
   236→      ifNull(round(med_response, 2), 0) as median_response_time_sec,
   237→      round(sum_quick_responses * 100.0 / if(sum_interactions > 0, sum_interactions, 1), 2) as quick_response_rate,
   238→      round(sum_long_pauses * 100.0 / if(sum_interactions > 0, sum_interactions, 1), 2) as long_pause_rate,
   239→      round(cnt_subagents * 100.0 / if(cnt_sessions > 0, cnt_sessions, 1), 2) as subagents_adoption_rate,
   240→      round(cnt_skills * 100.0 / if(cnt_sessions > 0, cnt_sessions, 1), 2) as skills_adoption_rate,
   241→      round(cnt_slash * 100.0 / if(cnt_sessions > 0, cnt_sessions, 1), 2) as slash_commands_adoption_rate
   242→    FROM totals
   243→  `;
   244→
   245→	const results = await queryClickhouse<SessionAnalyticsSummary>(query);
   246→
   247→	const defaults: SessionAnalyticsSummary = {
   248→		total_sessions: 0,
   249→		total_interactions: 0,
   250→		avg_session_duration_min: 0,
   251→		avg_interactions_per_session: 0,
   252→		avg_response_time_sec: 0,
   253→		median_response_time_sec: 0,
   254→		quick_response_rate: 0,
   255→		long_pause_rate: 0,
   256→		subagents_adoption_rate: 0,
   257→		skills_adoption_rate: 0,
   258→		slash_commands_adoption_rate: 0,
   259→	};
   260→
   261→	if (results.length === 0) {
   262→		return defaults;
   263→	}
   264→
   265→	// Coalesce nulls from ClickHouse (AVG on 0 rows returns null despite ifNull)
   266→	const row = results[0] as Record<string, unknown> | undefined;
   267→	if (!row) return defaults;
   268→	return Object.fromEntries(
   269→		Object.entries(defaults).map(([key, def]) => [key, row[key] ?? def]),
   270→	) as SessionAnalyticsSummary;
   271→}
