   275→/**
   276→ * Get session analytics summary with period-over-period comparison
   277→ */
   278→export async function getSessionAnalyticsSummaryComparison(
   279→	orgId: string,
   280→	params: {
   281→		days?: number;
   282→		user_id?: string;
   283→		project_path?: string;
   284→	} = {},
   285→) {
   286→	const { days = 7, user_id, project_path } = params;
   287→	const org = escapeString(orgId);
   288→	const d = Number(days);
   289→	const previousDays = d * 2;
   290→
   291→	let filters = "";
   292→	if (user_id) {
   293→		filters += ` AND user_id = '${escapeString(user_id)}'`;
   294→	}
   295→	if (project_path) {
   296→		filters += ` AND project_path = '${escapeString(project_path)}'`;
   297→	}
   298→
   299→	const summarySQL = (dateCondition: string) => `
   300→    WITH totals AS (
   301→      SELECT
   302→        COUNT(*) as cnt_sessions,
   303→        ifNull(AVG(actual_duration_min), 0) as avg_duration,
   304→        ifNull(AVG(avg_period_sec), 0) as avg_response,
   305→        countIf(length(subagent_types) > 0) as cnt_subagents,
   306→        countIf(length(skills) > 0) as cnt_skills,
   307→        countIf(length(slash_commands) > 0) as cnt_slash
   308→      FROM rudel.session_analytics
   309→      WHERE ${dateCondition}
   310→        AND organization_id = '${org}'
   311→        ${filters}
   312→    )
   313→    SELECT
   314→      cnt_sessions as total_sessions,
   315→      ifNull(round(avg_duration, 2), 0) as avg_session_duration_min,
   316→      ifNull(round(avg_response, 2), 0) as avg_response_time_sec,
   317→      round(cnt_subagents * 100.0 / if(cnt_sessions > 0, cnt_sessions, 1), 2) as subagents_adoption_rate,
   318→      round(cnt_skills * 100.0 / if(cnt_sessions > 0, cnt_sessions, 1), 2) as skills_adoption_rate,
   319→      round(cnt_slash * 100.0 / if(cnt_sessions > 0, cnt_sessions, 1), 2) as slash_commands_adoption_rate
   320→    FROM totals
   321→  `;
   322→
   323→	const currentQuery = summarySQL(buildDateFilter(d));
   324→	const previousQuery = summarySQL(
   325→		`session_date >= now64(3) - INTERVAL ${previousDays} DAY AND session_date < now64(3) - INTERVAL ${d} DAY`,
   326→	);
   327→
   328→	const [currentData, previousData] = await Promise.all([
   329→		queryClickhouse<SessionSummaryComparisonPeriod>(currentQuery),
   330→		queryClickhouse<SessionSummaryComparisonPeriod>(previousQuery),
   331→	]);
   332→
   333→	const defaultPeriod: SessionSummaryComparisonPeriod = {
   334→		total_sessions: 0,
   335→		avg_session_duration_min: 0,
   336→		avg_response_time_sec: 0,
   337→		subagents_adoption_rate: 0,
   338→		skills_adoption_rate: 0,
   339→		slash_commands_adoption_rate: 0,
   340→	};
   341→
   342→	// Coalesce nulls from ClickHouse (AVG on 0 rows returns null despite ifNull)
   343→	const coalesce = (
   344→		row: SessionSummaryComparisonPeriod | undefined,
   345→	): SessionSummaryComparisonPeriod => {
   346→		if (!row) return { ...defaultPeriod };
   347→		return Object.fromEntries(
   348→			Object.entries(defaultPeriod).map(([key, def]) => [
   349→				key,
   350→				(row as unknown as Record<string, unknown>)[key] ?? def,
   351→			]),
   352→		) as SessionSummaryComparisonPeriod;
   353→	};
   354→	const current = coalesce(currentData[0]);
   355→	const previous = coalesce(previousData[0]);
   356→
   357→	const calculateChange = (curr: number, prev: number) => {
   358→		if (!prev || prev === 0) return 0;
   359→		return ((curr - prev) / prev) * 100;
   360→	};
   361→
   362→	const changes = {
   363→		total_sessions: calculateChange(
   364→			current.total_sessions || 0,
   365→			previous.total_sessions || 0,
   366→		),
   367→		avg_session_duration_min: calculateChange(
   368→			current.avg_session_duration_min || 0,
   369→			previous.avg_session_duration_min || 0,
   370→		),
   371→		avg_response_time_sec: calculateChange(
   372→			current.avg_response_time_sec || 0,
   373→			previous.avg_response_time_sec || 0,
   374→		),
   375→	};
   376→
   377→	return { current, previous, changes };
   378→}
