   437→    FROM rudel.session_analytics
   438→    WHERE ${buildDateFilter(d)}
   439→      AND organization_id = '${org}'
   440→      ${filters}
   441→
   442→    ORDER BY count DESC
   443→  `;
   444→
   445→	return queryClickhouse<{ bucket: string; count: number; percentage: number }>(
   446→		query,
   447→	);
