   470→export async function getSessionDimensionAnalysis(
   471→	orgId: string,
   472→	params: {
   473→		days?: number;
   474→		dimension: DimensionAnalysisInput["dimension"];
   475→		metric: DimensionAnalysisInput["metric"];
   476→		split_by?: DimensionAnalysisInput["dimension"];
   477→		limit?: number;
   478→		user_id?: string;
   479→		project_path?: string;
   480→	},
   481→) {
   482→	const {
   483→		days = 7,
   484→		dimension,
   485→		metric,
   486→		split_by,
   487→		limit = 10,
   488→		user_id,
   489→		project_path,
   490→	} = params;
   491→	const org = escapeString(orgId);
   492→	const d = Number(days);
   493→	const lim = Number(limit);
   494→
   495→	const metricExpression = METRIC_EXPRESSIONS[metric];
   496→
   497→	// Map dimension to SQL expression (for computed dimensions)
   498→	const dimensionExpressions: Record<string, string> = {
   499→		repository:
   500→			"if(git_remote != '', git_remote, if(package_name != '', package_name, project_path))",
   501→		used_skills: "if(length(skills) > 0, 1, 0)",
   502→		used_slash_commands: "if(length(slash_commands) > 0, 1, 0)",
   503→		used_subagents: "if(length(subagent_types) > 0, 1, 0)",
   504→	};
   505→
   506→	const dimensionExpression = dimensionExpressions[dimension] || dimension;
   507→	const splitByExpression = split_by
   508→		? dimensionExpressions[split_by] || split_by
   509→		: null;
   510→
   511→	let filters = "";
   512→	if (user_id) {
   513→		filters += ` AND user_id = '${escapeString(user_id)}'`;
   514→	}
   515→	if (project_path) {
   516→		filters += ` AND project_path = '${escapeString(project_path)}'`;
   517→	}
   518→
   519→	let query: string;
   520→
   521→	if (split_by) {
   522→		query = `
   523→      SELECT
   524→        ${dimensionExpression} as dimension_value,
   525→        ${splitByExpression} as split_value,
   526→        ${metricExpression} as metric_value
   527→      FROM rudel.session_analytics
   528→      WHERE ${buildDateFilter(d)}
   529→        AND organization_id = '${org}'
   530→        ${filters}
   531→      GROUP BY dimension_value, split_value
   532→      ORDER BY metric_value DESC
   533→    `;
   534→	} else {
   535→		query = `
   536→      SELECT
   537→        ${dimensionExpression} as dimension_value,
   538→        ${metricExpression} as metric_value
   539→      FROM rudel.session_analytics
   540→      WHERE ${buildDateFilter(d)}
   541→        AND organization_id = '${org}'
   542→        ${filters}
   543→      GROUP BY dimension_value
   544→      ORDER BY metric_value DESC
   545→      LIMIT ${lim}
   546→    `;
   547→	}
   548→
   549→	interface DimensionRow {
   550→		dimension_value: string;
   551→		split_value?: string;
   552→		metric_value: number;
   553→	}
   554→
   555→	const results = await queryClickhouse<DimensionRow>(query);
   556→
   557→	if (split_by) {
   558→		const grouped = new Map<string, Record<string, number>>();
   559→		const totalMetric = new Map<string, number>();
   560→
   561→		for (const row of results) {
   562→			const dimVal = String(row.dimension_value);
   563→			const splitVal = String(row.split_value);
   564→			const metricVal = Number(row.metric_value);
   565→
   566→			if (!grouped.has(dimVal)) {
   567→				grouped.set(dimVal, {});
   568→				totalMetric.set(dimVal, 0);
   569→			}
   570→
   571→			const group = grouped.get(dimVal);
   572→			if (group) group[splitVal] = metricVal;
   573→			totalMetric.set(dimVal, (totalMetric.get(dimVal) || 0) + metricVal);
   574→		}
   575→
   576→		const finalData = Array.from(grouped.entries())
   577→			.map(([dimension_value, split_values]) => ({
   578→				dimension_value,
   579→				split_values,
   580→				_total: totalMetric.get(dimension_value) || 0,
   581→			}))
   582→			.sort((a, b) => b._total - a._total)
   583→			.slice(0, lim)
   584→			.map(({ dimension_value, split_values }) => ({
   585→				dimension_value,
   586→				split_values,
   587→			}));
   588→
   589→		return finalData;
   590→	}
   591→
   592→	return results.map((row) => ({
   593→		dimension_value: String(row.dimension_value),
   594→		metric_value: Number(row.metric_value),
   595→	}));
   596→}
