   408→        AND organization_id = '${org}'
   409→        ${filters}
   410→    )
   411→    SELECT
   412→      'Instant (< 5s)' as bucket,
   413→      SUM(quick_responses) as count,
   414→      round(SUM(quick_responses) * 100.0 / (SELECT total_count FROM total), 2) as percentage
   415→    FROM rudel.session_analytics
   416→    WHERE ${buildDateFilter(d)}
   417→      AND organization_id = '${org}'
   418→      ${filters}
   419→
   420→    UNION ALL
   421→
   422→    SELECT
   423→      'Normal (5-60s)' as bucket,
   424→      SUM(normal_responses) as count,
   425→      round(SUM(normal_responses) * 100.0 / (SELECT total_count FROM total), 2) as percentage
   426→    FROM rudel.session_analytics
   427→    WHERE ${buildDateFilter(d)}
   428→      AND organization_id = '${org}'
   429→      ${filters}
   430→
   431→    UNION ALL
   432→
   433→    SELECT
   434→      'Long Pause (> 5m)' as bucket,
   435→      SUM(long_pauses) as count,
   436→      round(SUM(long_pauses) * 100.0 / (SELECT total_count FROM total), 2) as percentage
   437→    FROM rudel.session_analytics
   438→    WHERE ${buildDateFilter(d)}
   439→      AND organization_id = '${org}'
   440→      ${filters}
   441→
   442→    ORDER BY count DESC
   443→  `;
   444→
   445→	return queryClickhouse<{ bucket: string; count: number; percentage: number }>(
   446→		query,
