   453→
   454→// Map metric to SQL expression
   455→const METRIC_EXPRESSIONS: Record<DimensionAnalysisInput["metric"], string> = {
   456→	session_count: "COUNT(*)",
   457→	avg_duration: "round(AVG(actual_duration_min), 2)",
   458→	total_duration: "round(SUM(actual_duration_min) / 60, 2)",
   459→	avg_interactions: "round(AVG(total_interactions), 2)",
