   462→	median_response_time: "round(AVG(median_period_sec), 2)",
   463→	avg_tokens: "round(AVG(total_tokens), 0)",
   464→	total_tokens: "SUM(total_tokens)",
   465→	avg_success_score: "round(AVG(success_score), 2)",
